"""
Generates 500 wind turbine tags inspired by IEC 61400-25 logical nodes.
Outputs both CSV and JSON.
"""
import csv
import json

tags = []
_id = [1]  # mutable counter

def add(name, desc, unit, dtype, vmin, vmax, category, interval=1, critical=False):
    tags.append({
        "tag_id": _id[0],
        "tag_name": name,
        "description": desc,
        "unit": unit,
        "data_type": dtype,
        "min_value": vmin,
        "max_value": vmax,
        "category": category,
        "update_interval_sec": interval,
        "is_critical": critical,
    })
    _id[0] += 1

