# Output to CSV and JSON
# =========================================================
print(f"Total tags generated: {len(tags)}")

# Save CSV
with open("/home/claude/wind_turbine_tags.csv", "w", newline="") as f:
    fieldnames = ["tag_id","tag_name","description","unit","data_type","min_value","max_value","category","update_interval_sec","is_critical"]
    w = csv.DictWriter(f, fieldnames=fieldnames)
    w.writeheader()
    for t in tags:
        w.writerow(t)

# Save JSON
with open("/home/claude/wind_turbine_tags.json", "w") as f:
    json.dump(tags, f, indent=2)

# Summary by category
from collections import Counter
counts = Counter(t["category"] for t in tags)
print("\nTags per category:")
for c, n in counts.items():
    print(f"  {c}: {n}")